using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");
        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_Null_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithTitle()
    {
        var result = _formatter.BuildGreeting("Smith", "Dr.");
        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");
        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");
        StringAssert.DoesNotMatch(result, new Regex(@"^-|-$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceOnly_Throws()
    {
        _formatter.GenerateSlug("   ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollar()
    {
        var result = _formatter.FormatCurrency(9.99m);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(10m);
        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");
        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_MatchesFormat()
    {
        var result = _formatter.FormatCurrency(42m);
        StringAssert.Matches(result, new Regex(@"^\$\d+\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);
        StringAssert.Contains(result, "-");
    }
}

